import React, { useState, useEffect } from "react";
import { Link } from "react-scroll";
import "../styles/Navbar.css";

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 0.9 * window.screen.availWidth);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 0.9 * window.screen.availWidth);
    };
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  return (
    <nav className="navbar">
      <div className="navbar-logo">
        <Link to="home" smooth={true} duration={500}>
          <img src="./images/logo.png" alt="Logo" />
        </Link>
      </div>

      {isMobile ? (
        <div className="hamburger" onClick={() => setIsOpen(!isOpen)}>
          &#9776;
        </div>
      ) : (
        <ul className="navbar-links">
          {["HOME", "ABOUT US", "AREAS OF PRACTICE", "OUR PROFESSIONALS", "NEWS & ARTICLES", "GALLERY", "CONTACT US"].map((section) => (
            <li key={section}>
              <Link to={section} smooth={true} duration={500} activeClass="active">
                {section.replace(/^-\w/, (c) => c.toUpperCase()).replace("-", " ")}
              </Link>
            </li>
          ))}
        </ul>
      )}

      {isMobile && isOpen && (
        <ul className="mobile-menu">
          {["HOME", "ABOUT US", "AREAS OF PRACTICE", "OUR PROFESSIONALS", "NEWS & ARTICLES", "GALLERY", "CONTACT US"].map((section) => (
            <li key={section} onClick={() => setIsOpen(false)}>
              <Link to={section} smooth={true} duration={500} activeClass="active">
                {section.replace(/^-\w/, (c) => c.toUpperCase()).replace("-", " ")}
              </Link>
            </li>
          ))}
        </ul>
      )}
    </nav>
  );
};

export default Navbar;
